public class Animal {
    public void speak() {
        System.out.println("Animal speaks");
    }
    public void breathe() {
        System.out.println("Animal breathes");
    }
}

public class Dog extends Animal {
    @Override
    public void speak() {
        System.out.println("Dog barks");
    }
    public void fetch() {
        System.out.println("Dog fetches");
    }
}

public class Test {
    public static void main(String[] args) {
        Animal a = new Dog();   // upcast: Dog → Animal (automatic)

        a.speak();              // Dog barks   ← runtime type = Dog
        a.breathe();            // Animal breathes ← inherited, not overridden
        // a.fetch();           // COMPILE ERROR: fetch() not in Animal
    }
}

public class Test {
    public static void main(String[] args) {
        Animal a1 = new Dog();   // actual type: Dog
        Animal a2 = new Animal(); // actual type: Animal

        // Safe downcast
        if (a1 instanceof Dog) {
            Dog d = (Dog) a1;   // OK: actual type IS Dog
            d.fetch();          // Dog fetches
        }

        // Unsafe downcast — would throw ClassCastException
        try {
            Dog d2 = (Dog) a2;  // actual type is Animal, NOT Dog!
            d2.fetch();
        } catch (ClassCastException e) {
            System.out.println("ClassCastException caught!");
        }
    }
}

public class Vehicle {
    String type = "vehicle";
    public String describe() { return "I am a " + type; }
    public static String category() { return "Vehicle category"; }
}

public class Car extends Vehicle {
    String type = "car";   // shadows Vehicle.type
    @Override
    public String describe() { return "I am a " + type; }
    public static String category() { return "Car category"; }
}

public class Demo {
    public static void main(String[] args) {
        Vehicle v = new Car();
        System.out.println(v.describe());    // Line A
        System.out.println(v.category());   // Line B
        System.out.println(v.type);          // Line C

        Car c = new Car();
        System.out.println(c.describe());    // Line D
        System.out.println(c.category());   // Line E
        System.out.println(c.type);          // Line F
    }
}
// Line A: "I am a car"     ← dynamic dispatch → Car.describe(), Car.type used inside
// Line B: "Vehicle category" ← static → declared type Vehicle
// Line C: "vehicle"         ← field → declared type Vehicle (no dispatch for fields)
// Line D: "I am a car"     ← Car.describe()
// Line E: "Car category"   ← static → declared type Car
// Line F: "car"             ← field → declared type Car

