// Create a Shape hierarchy:
// Shape (base) → has name(), area(), perimeter()
// Circle → area = PI*r*r, perimeter = 2*PI*r
// Rectangle → area = w*h, perimeter = 2*(w+h)
// Triangle (sides a, b, c) → perimeter = a+b+c,
//                             area = Heron's formula
//
// Write processAll(Shape[] shapes) that prints:
//   "[name]: area=[area], perimeter=[perimeter]"
// for each shape (rounded to 2 decimal places).
// Demonstrate with: Circle(7), Rectangle(4,9), Triangle(3,4,5)

sections.solution:
public class Shape {
    public String name()      { return "Shape"; }
    public double area()      { return 0.0; }
    public double perimeter() { return 0.0; }
}

class Circle extends Shape {
    double r;
    public Circle(double r) { this.r = r; }
    @Override public String name()      { return "Circle"; }
    @Override public double area()      { return Math.PI * r * r; }
    @Override public double perimeter() { return 2 * Math.PI * r; }
}

class Rectangle extends Shape {
    double w, h;
    public Rectangle(double w, double h) { this.w=w; this.h=h; }
    @Override public String name()      { return "Rectangle"; }
    @Override public double area()      { return w * h; }
    @Override public double perimeter() { return 2*(w+h); }
}

class Triangle extends Shape {
    double a, b, c;
    public Triangle(double a, double b, double c) {
        this.a=a; this.b=b; this.c=c;
    }
    @Override public String name()      { return "Triangle"; }
    @Override public double perimeter() { return a+b+c; }
    @Override public double area() {
        double s = (a+b+c) / 2;
        return Math.sqrt(s*(s-a)*(s-b)*(s-c));
    }
}

public class ShapeCalculator {
    static void processAll(Shape[] shapes) {
        for (Shape s : shapes) {
            System.out.printf("%s: area=%.2f, perimeter=%.2f%n",
                s.name(), s.area(), s.perimeter());
        }
    }
    public static void main(String[] args) {
        Shape[] shapes = {
            new Circle(7),
            new Rectangle(4, 9),
            new Triangle(3, 4, 5)
        };
        processAll(shapes);
    }
}
// Circle: area=153.94, perimeter=43.98
// Rectangle: area=36.00, perimeter=26.00
// Triangle: area=6.00, perimeter=12.00
